function handleMayuanDocUpload(event){
var file=event&&event.target&&event.target.files?event.target.files[0]:null;
if(!file)return;
if(!apiConfig.apikey||apiConfig.apikey.length<10){
setMayuanDocStatus("请先完成模型配置，再上传文档","error");
showApiConfigPrompt();
return;
}
if(!apiConfig.model){
setMayuanDocStatus("请先选择模型，再上传文档","error");
showApiConfigPrompt();
return;
}
setMayuanDocStatus("正在读取："+file.name,"loading");
getMayuanDocumentText(file).then(function(text){
text=String(text||"").replace(/\u0000/g,"").replace(/[ \t]+\n/g,"\n").replace(/\n{4,}/g,"\n\n\n").trim();
if(!text){throw new Error("没有识别到可用文字内容")}
addMessage("user","📎 已上传文档："+file.name+"\n请先帮我总结文档内容，并按马源内容体系提炼可用素材。");
showTyping();
setMayuanDocStatus("正在提炼文档内容","loading");
return summarizeMayuanDocument(file.name,text);
}).then(function(summary){
hideTyping();
var nextText=chatKey==="1-3"?"\n\n是否需要我根据以上内容，继续生成脚本、内容专项方案或素材测试计划？":"\n\n是否需要我根据以上内容，继续生成一条30-60秒的引流视频脚本？";
addMessage("assistant",summary+nextText);
setMayuanDocStatus(chatKey==="1-3"?"文档提炼完成，可继续生成专项方案":"文档提炼完成，可继续生成引流视频","ok");
}).catch(function(err){
if(isAbortError(err)){showGenerationAbortNotice();return}
hideTyping();
setMayuanDocStatus(err.message||"文档读取失败","error");
if(chatOpen){addMessage("assistant","❌ 文档总结失败："+(err.message||"请稍后重试"))}
});
}

