function getKyrieScriptGenerationSupplement(){
return "\n\n# Kyrie脚本生成数量完整性硬性规则\n当用户要求生成整场直播脚本、直播逐字稿、逼单话术、憋单话术、互动话术或完整带货脚本时，数量类板块必须严格补齐，不能省略、合并或用“等”代替。\n\n必须严格执行：\n1. 【逼单话术10条】必须编号1-10，每条都是不同角度、可直接在直播间念的完整话术。\n2. 【憋单话术5条】必须编号1-5，不能只生成1条。5条建议分别覆盖：倒计时、名额/库存、福利截止、价格/权益恢复、错过成本或返场前收口。\n3. 【评论互动话术20条】必须编号1-20，每条要短、口语化、适合直播间直接引导评论。\n4. 【用户抗拒点答疑话术】至少覆盖价格、效果、时间、上手难度、服务、售后、正版、适不适合我8类。\n\n输出前必须自检数量；如果任何板块数量不足，先补齐再输出。内容太长时可以压缩每条长度，但不允许减少条数。";
}
function getKyrieDryGoodsHookSupplement(){
return "\n\n# Kyrie干货主题产品钩子规则\n生成干货主题、干货逐字稿或整场直播脚本时，干货主题的结构必须调整为：痛点现象 -> 用户场景 -> 背后原因 -> 危害放大 -> 简单方法 -> 产品钩子。\n\n这里的【产品钩子】不是正式带货衔接，也不是直接卖课；正式的带货衔接仍然放在独立的“带货衔接/干货到卖课的衔接”板块中。产品钩子的作用是：在每个干货讲解完，或干货讲解过程中，用一句轻量、自然、直播感强的话，让用户提前知道后面会有课程/系统方法承接，形成循序渐进的接受过程。\n\n产品钩子写法要求：\n1. 每个干货主题结束后至少设置1句产品钩子；如果干货较长，也可以在讲解中间轻轻埋1句。\n2. 语气要像老师自然提醒，不要强行推销，不要上价格，不要讲福利，不要逼单。\n3. 话术方向类似：“刚才我讲的只是冰山一角，更完整的拆解和训练方法都在课程里面，我后面会带大家系统说。”\n4. 产品钩子要为后面的洗认知、给场景、上价值做铺垫，不能替代正式带货衔接。\n5. 不要再把干货主题最后一步写成“转课程衔接”。";
}
function getActiveChatMaxTokens(defaultTokens){
if(isKyrieScriptAgent())return 6500;
return defaultTokens;
}
function getKyrieDataScreenshotPrompt(fileName){
return "用户上传了一张直播后数据截图，文件名："+fileName+"。\n\n请先识别截图中的可见数据，不要编造看不清或不存在的数据。如果当前模型无法读取图片内容，请明确说明“当前模型无法识别该截图内容”，并提示用户更换支持视觉的模型或手动输入关键数据。\n\n如果能读取，请按以下结构输出：\n1. 截图可见数据摘要：在线、停留、互动、点击、成交、转化等能识别到的指标。\n2. 异常指标判断：哪些数据偏低、偏高或不匹配。\n3. 直播问题诊断：从流量承接、停留、互动、商品点击、成交转化、老师节奏、中控动作分析原因。\n4. Kyrie 方法论诊断：信任建立、痛点唤醒、认知改变、价值呈现、成交转化哪一环最弱。\n5. 下一场优化动作：按优先级列出 5-8 条可执行动作。\n6. 需要补充的数据：列出为了更准确复盘还需要用户提供什么。";
}
function callKyrieImageReviewAPI(fileName,dataUrl){
var messages=[
{role:"system",content:getKyrieReviewPromptBase()},
{role:"user",content:[
{type:"text",text:getKyrieDataScreenshotPrompt(fileName)},
{type:"image_url",image_url:{url:dataUrl}}
]}
];
return apiFetch(apiConfig.endpoint,{method:"POST",headers:{"Content-Type":"application/json","Authorization":"Bearer "+apiConfig.apikey},body:JSON.stringify({model:apiConfig.model,messages:messages,temperature:.2,max_tokens:3500})}).then(function(r){return r.json()}).then(function(data){
if(data.error){throw new Error(data.error.message||"API 返回错误")}
if(!data.choices||!data.choices[0]||!data.choices[0].message){throw new Error("API 返回格式异常")}
return data.choices[0].message.content||"";
});
}
function isKyrieImageFile(file){
return !!file&&(/image\/(png|jpeg|webp)/.test(file.type)||/\.(png|jpe?g|webp)$/i.test(file.name||""));
}
function isKyrieDocumentFile(file){
return !!file&&(/\.(txt|md|csv|json|docx|pdf)$/i.test(file.name||"")||/^text\//.test(file.type)||/application\/(json|pdf)/.test(file.type)||file.type==="application/vnd.openxmlformats-officedocument.wordprocessingml.document");
}
function processKyrieImageFile(file){
if(!file)return;
if(!ensureKyrieUploadReady())return;
if(file.size>8*1024*1024){setMayuanDocStatus("图片超过 8MB，请压缩后上传","error");return}
if(!isKyrieImageFile(file)){setMayuanDocStatus("请上传 png、jpg、jpeg 或 webp 图片","error");return}
setMayuanDocStatus("正在读取截图："+file.name,"loading");
readFileAsDataUrl(file).then(function(dataUrl){
addMessage("user","📊 已上传直播数据截图："+file.name+"\n请按 Kyrie 直播方法论帮我做直播后数据复盘。");
showTyping();
setMayuanDocStatus("正在识别截图并分析数据","loading");
return callKyrieImageReviewAPI(file.name,dataUrl);
}).then(function(result){
hideTyping();
addMessage("assistant",result);
setMayuanDocStatus("截图复盘完成，可继续补充数据或逐字稿","ok");
}).catch(function(err){
if(isAbortError(err)){showGenerationAbortNotice();return}
hideTyping();
var msg=err.message||"截图识别失败";
setMayuanDocStatus(msg,"error");
addMessage("assistant","❌ 截图分析失败："+msg+"\n\n如果当前模型不支持识图，请更换支持视觉的模型，或手动输入在线、停留、互动、点击、成交等关键数据。");
});
}
function handleKyrieImageUpload(event){
var file=event&&event.target&&event.target.files?event.target.files[0]:null;
processKyrieImageFile(file);
}
function summarizeKyrieTranscriptDocument(fileName,text){
var chunks=splitMayuanDocumentText(text,9000);
var system=getKyrieReviewPromptBase()+"\n\n你正在分析用户上传的直播逐字稿或直播复盘文本。重点关注时间戳、话术结构、互动节点、带货衔接、成交话术、节奏问题和下一场优化动作。";
var singleTask="请分析这份直播逐字稿/复盘文档，并按 Kyrie 直播方法论做诊断。\n\n文档名称："+fileName+"\n\n输出结构：\n1. 文档核心摘要\n2. 时间线诊断：按时间戳或话术阶段梳理关键节点\n3. 留人问题：开场、停留、节奏、用户注意力\n4. 干货节奏：痛点现象、用户场景、背后原因、危害放大、简单方法是否完整\n5. 带货衔接诊断：是否完成洗认知 -> 给场景 -> 上价值，哪里生硬或缺失\n6. 互动设计：哪些地方缺少低成本互动，应该插入什么互动句\n7. 成交话术：课程介绍、福利、核心卖点、逼单/憋单/返场的问题\n8. 老师状态与表达：交流感、真诚感、节奏感、笃定感\n9. 可直接替换的话术：给出关键位置的改写版本\n10. 下一场直播优先级优化清单\n11. 还需要用户补充哪些数据\n\n文档内容：\n"+text;
if(chunks.length<=1){
return callMayuanDocumentSummaryAPI([{role:"system",content:system},{role:"user",content:singleTask}],4000);
}
var partials=[];
var chain=Promise.resolve();
chunks.forEach(function(chunk,idx){
chain=chain.then(function(){
setMayuanDocStatus("正在分析逐字稿第 "+(idx+1)+"/"+chunks.length+" 段","loading");
var chunkPrompt="这是直播逐字稿/复盘文档的第 "+(idx+1)+"/"+chunks.length+" 段。请只提炼本段中与 Kyrie 复盘相关的信息：时间戳、话术结构、互动节点、干货节奏、带货衔接、成交话术、老师状态、明显问题和可替换话术。不要泛泛总结。\n\n文档名称："+fileName+"\n\n本段内容：\n"+chunk;
return callMayuanDocumentSummaryAPI([{role:"system",content:system},{role:"user",content:chunkPrompt}],2500).then(function(summary){partials.push("第"+(idx+1)+"段分析：\n"+summary)});
});
});
return chain.then(function(){
setMayuanDocStatus("正在合成完整复盘诊断","loading");
var mergePrompt="请把以下分段分析合成为一份完整的 Kyrie 直播后复盘报告。\n\n文档名称："+fileName+"\n\n输出结构：\n1. 文档核心摘要\n2. 时间线诊断\n3. 留人问题\n4. 干货节奏\n5. 带货衔接诊断：必须检查洗认知 -> 给场景 -> 上价值\n6. 互动设计\n7. 成交话术\n8. 老师状态与表达\n9. 可直接替换的话术\n10. 下一场直播优先级优化清单\n11. 还需要补充哪些数据\n\n分段分析：\n"+partials.join("\n\n");
return callMayuanDocumentSummaryAPI([{role:"system",content:system},{role:"user",content:mergePrompt}],4500);
});
}
function processKyrieDocFile(file){
if(!file)return;
if(!ensureKyrieUploadReady())return;
if(!isKyrieDocumentFile(file)){setMayuanDocStatus("请上传 txt、md、csv、json、docx 或 pdf 文档","error");return}
setMayuanDocStatus("正在读取逐字稿："+file.name,"loading");
getMayuanDocumentText(file).then(function(text){
text=String(text||"").replace(/\u0000/g,"").replace(/[ \t]+\n/g,"\n").replace(/\n{4,}/g,"\n\n\n").trim();
if(!text){throw new Error("没有识别到可用文字内容")}
addMessage("user","📎 已上传直播逐字稿/复盘文档："+file.name+"\n请结合 Kyrie 直播方法论分析诊断。");
showTyping();
setMayuanDocStatus("正在分析逐字稿内容","loading");
return summarizeKyrieTranscriptDocument(file.name,text);
}).then(function(summary){
hideTyping();
addMessage("assistant",summary+"\n\n你也可以继续补充直播后台数据截图，我会把数据表现和逐字稿话术放在一起复盘。");
setMayuanDocStatus("逐字稿复盘完成，可继续上传截图或补充数据","ok");
}).catch(function(err){
if(isAbortError(err)){showGenerationAbortNotice();return}
hideTyping();
setMayuanDocStatus(err.message||"逐字稿读取失败","error");
if(chatOpen){addMessage("assistant","❌ 逐字稿分析失败："+(err.message||"请稍后重试"))}
});
}
function handleKyrieDocUpload(event){
var file=event&&event.target&&event.target.files?event.target.files[0]:null;
processKyrieDocFile(file);
}
function handleKyrieReviewFile(file){
if(!file||!isKyrieReviewTask())return false;
if(isKyrieImageFile(file)){processKyrieImageFile(file);return true}
if(isKyrieDocumentFile(file)){processKyrieDocFile(file);return true}
setMayuanDocStatus("暂不支持该文件，请上传数据截图或逐字稿文档","error");
return true;
}

