function xuehuiCallAPI(systemPrompt,userPrompt,callback,opts){
if(!apiConfig.apikey||apiConfig.apikey.length<10){showApiConfigPrompt();return}
if(/生成|重写|优化|文案|脚本|口播|逐字稿/.test(String(systemPrompt||"")+String(userPrompt||""))){
systemPrompt=appendCopyCoherenceRule(systemPrompt);
}
if(/生成|重写|优化|文案|脚本|口播|逐字稿/.test(String(userPrompt||""))&&!/JSON|json|只输出JSON数组|推荐1-2个|输出纯JSON数组|输出格式：\{/.test(String(userPrompt||""))){
userPrompt=appendCopyCoherenceRule(userPrompt);
}
var msgs=[{role:"system",content:systemPrompt},{role:"user",content:userPrompt}];
opts=opts||{};
apiFetch(apiConfig.endpoint,{method:"POST",headers:{"Content-Type":"application/json","Authorization":"Bearer "+apiConfig.apikey},body:JSON.stringify({model:apiConfig.model,messages:msgs,temperature:opts.temperature||0.8,max_tokens:opts.max_tokens||4000,response_format:opts.response_format||void 0})})
.then(function(r){return r.json()})
.then(function(data){
 if(data.error){alert("API error: "+data.error.message);callback({error:data.error,raw:""});return}
 if(!data.choices||!data.choices[0]||!data.choices[0].message){callback({error:{message:"API 返回格式异常"},raw:""});return}
 var text=data.choices[0].message.content;
 try{var t=text.replace(/^```(?:json)?\s*\n?/,"").replace(/\n?```\s*$/,"");var json=JSON.parse(t);callback(json)}catch(e){callback({raw:text})}
}).catch(function(e){
 if(isAbortError(e)){showGenerationAbortNotice();restoreAllGenerationButtons();return}
 alert("request failed: "+e.message);callback({error:{message:e.message},raw:""})
});
}













