function normalizeQuickChips(items){
var seen={},out=[];
(items||[]).forEach(function(item){
var text=String(item||"").replace(/\s+/g," ").trim();
if(!text||seen[text]||text.length>34)return;
seen[text]=true;out.push(text);
});
return out.slice(0,5);
}
