function getStrictDurationRule(duration){
duration=String(duration||"").trim();
if(/15-30秒|30秒以内/.test(duration))return "【视频时长硬性要求】目标时长："+duration+"。纯口播文案必须控制在80-140字，6-10句，每句不超过25字；开头0-3秒必须完成钩子，主体只保留1个核心卖点或1个核心观点，禁止写成长篇。";
if(/30-60秒/.test(duration))return "【视频时长硬性要求】目标时长："+duration+"。纯口播文案必须控制在150-260字，10-16句，每句不超过25字；结构必须完整覆盖开头钩子、痛点/场景、核心价值、转化或收尾。";
if(/60-90秒|60秒以上/.test(duration))return "【视频时长硬性要求】目标时长："+duration+"。纯口播文案必须控制在260-420字，16-26句，每句不超过25字；允许展开2-3个卖点或案例，但不能超过420字。";
if(/90-120秒/.test(duration))return "【视频时长硬性要求】目标时长："+duration+"。纯口播文案必须控制在420-620字，26-38句，每句不超过25字；必须有完整铺垫、场景、价值展开和自然收口。";
if(/120秒以上|2分钟|两分钟/.test(duration))return "【视频时长硬性要求】目标时长："+duration+"。纯口播文案必须不少于620字，建议620-900字；结构要完整，允许分2-3个自然段，但每行仍必须是可朗读正文。";
return "";
}
function getDurationRuleFromText(text){
text=String(text||"");
var match=text.match(/(15-30秒|30秒以内|30-60秒|60-90秒|90-120秒|120秒以上|60秒以上|2分钟|两分钟)/);
return match?getStrictDurationRule(match[1]):"";
}
function getCopyCoherenceRule(){
return "\n\n# 口播逻辑质量硬性要求\n这条规则不改变当前板块的方法论，只负责检查文案是否像真人会说、是否顺着一个逻辑往前走。\n1. 先服从当前板块已选的方法论、模板、钩子、人设、手法和时长要求，不要把所有文案固定成同一种结构。\n2. 每条文案只能有一个主线问题或一个主线需求。可以提到辅助痛点，但不能把多个无关痛点、卖点和效果承诺硬塞在一起。\n3. 输出口播前，先在内部判断最适合的推进方式，可以是“痛点->原因->解决”、“场景->冲突->转折”、“旧方案->新方案->证明”、“故事->观点->行动”等，不要求固定顺序，但必须自然承接。\n4. 每一段必须回答上一段留下的问题，或者推动下一步。不能突然从痛点跳到产品参数，不能从用户体验突然变成品牌说明书。\n5. 卖点必须翻译成用户能感知的体验、场景、证据或判断理由。不要连续堆数字、功效词、形容词。\n6. 涉及护肤、健康、教育、收益等高敏领域时，避免“换皮、治好、全退散、保证、再也不会、一定有效”等绝对化表达，改成“更稳定、减少、帮助、改善、适合、我的感受是、可以先观察”等稳妥表达。\n7. 口播要像一个稳定身份的人说出来。用户视角就保持真实体验，商家视角就保持产品解释，专家视角就保持专业判断，不要中途切换身份。\n8. 口播标点必须服务真人说话的停顿和语气。不要把每个5-10个字的短信息都用句号切断；同一层意思优先用逗号、顿号、分号或合并成一句，让一句话有完整的起承转合。\n9. 问号只用于完整提问，不要写成“保温？出门一小时就凉了。”这类碎片问句。应该改成“说是保温杯，结果出门一小时水就凉了。”或者“你有没有遇到过，明明买的是保温杯，出门一小时水就凉了？”\n10. 纯口播文案每一行可以是一句完整话，也可以是一组自然停顿，但不能像清单、PPT标题或参数堆叠。参数出现后必须马上接用户感知，例如“316不锈钢”后说明“不容易有铁锈味，热水、咖啡放进去也更安心”。\n11. 输出前自检：如果句子顺序可以随意调换、删掉中间句也不影响理解、每句都像标题或广告口号，或者标点读起来一卡一顿，说明逻辑和口播感不合格，必须先重写。\n";
}
function appendCopyCoherenceRule(text){
text=String(text||"");
if(text.indexOf("口播逻辑质量硬性要求")<0)text+=getCopyCoherenceRule();
if(text.indexOf("品类常识与事实边界硬性要求")<0)text+=getProductCommonSenseRule();
return text;
}
function getProductCommonSenseRule(){
return "\n\n# 品类常识与事实边界硬性要求\n这条规则不改变当前板块的方法论，只负责防止文案为了情绪冲击写出不符合常识、因果不成立或产品承接不了的内容。\n1. 输出前必须先判断产品品类真实能解决什么、不能解决什么。产品只能承接真实卖点，不能把不属于该品类的身体变化、人生结果、成绩结果、财富结果或医疗效果写进去。\n2. 痛点、原因、产品卖点之间必须有真实因果。不要为了押韵、反差、段子感或强情绪，写出无法解释的句子。\n3. 比如护眼灯可以写照明更舒适、减少眩光、读写环境更稳定、帮助缓解用眼疲劳，但不能写“把眼睛养大”“治好近视”“恢复视力”。护肤品可以写肤感、状态、保湿、泛红观感改善，不能写“换皮”“治好烂脸”。教育产品可以写方法、规划、陪伴和学习习惯，不能保证成绩或升学结果。\n4. 如果用户没有提供足够证据，不要编造具体数据、用户案例、权威背书、检测报告、销量排名、真实反馈或功效承诺。\n5. 可以用口语化、冲突感和场景感，但每一句都必须像真实用户、真实商家或真实专家会说的话。夸张表达必须能被现实场景解释；解释不了就改成具体场景、真实体验或保守表达。\n6. 输出前自检：如果某句话换成普通人听会觉得“不可能”“这和产品没关系”“这像乱编的”，必须先重写。";
}
